import{_ as d,o as e,c as a,a4 as r}from"./chunks/framework.BybBnFXO.js";const m=JSON.parse('{"title":"过渡金属离子致色","description":"","frontmatter":{"title":"过渡金属离子致色","colorCause":"transition-metal"},"headers":[],"relativePath":"zh/color-causes/transition-metal.md","filePath":"zh/color-causes/transition-metal.md","lastUpdated":1784176423000}'),o={name:"zh/color-causes/transition-metal.md"};function i(n,t,l,s,h,c){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="过渡金属离子致色" tabindex="-1">过渡金属离子致色 <a class="header-anchor" href="#过渡金属离子致色" aria-label="Permalink to &quot;过渡金属离子致色&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>过渡金属离子（如 Cr、Fe、Mn、Co、Ni、V、Cu、Ti）含有未填满的 d 或 f 电子层。当这些离子进入晶格取代主晶格中的位置（如 Al、Si、 Mg）时，其能级被晶场劈裂为多组 d-d 跃迁。吸收可见光特定波段后， 透射或反射光中残留的颜色即为我们看到的颜色。这是宝石界最重要 的致色机制，约 70% 的有色宝石属此类。</p><h2 id="致色机制" tabindex="-1">致色机制 <a class="header-anchor" href="#致色机制" aria-label="Permalink to &quot;致色机制&quot;">​</a></h2><p><strong>晶场理论</strong>：过渡金属离子周围配位阴离子（O²⁻、OH⁻、F⁻）产生 静电场，使简并的 d 轨道分裂为不同能级。电子在这些分裂能级之间 跃迁吸收特定波长光子。配位几何（八面体 vs 四面体）、键长、键角 决定能级差，从而决定吸收波长与最终颜色。</p><h2 id="示例宝石" tabindex="-1">示例宝石 <a class="header-anchor" href="#示例宝石" aria-label="Permalink to &quot;示例宝石&quot;">​</a></h2><table tabindex="0"><thead><tr><th>宝石</th><th>致色元素</th><th>化学式宿主</th><th>颜色</th></tr></thead><tbody><tr><td>Ruby / 红宝石</td><td>Cr³⁺</td><td>Al₂O₃</td><td>red</td></tr><tr><td>Emerald / 祖母绿</td><td>Cr³⁺ / V³⁺</td><td>Be₃Al₂Si₆O₁₈</td><td>green</td></tr><tr><td>Sapphire (blue) / 蓝宝石</td><td>Fe²⁺–Ti⁴⁺</td><td>Al₂O₃</td><td>blue</td></tr><tr><td>Aquamarine / 海蓝宝</td><td>Fe²⁺</td><td>Be₃Al₂Si₆O₁₈</td><td>blue</td></tr><tr><td>Peridot / 橄榄石</td><td>Fe²⁺</td><td>(Mg,Fe)₂SiO₄</td><td>olive-green</td></tr><tr><td>Tsavorite / 沙弗莱</td><td>V³⁺ / Cr³⁺</td><td>Ca₃Al₂Si₃O₁₂</td><td>green</td></tr><tr><td>Alexandrite / 亚历山大石</td><td>Cr³⁺</td><td>BeAl₂O₄</td><td>green / red (color-change)</td></tr><tr><td>Rhodonite / 蔷薇辉石</td><td>Mn²⁺</td><td>MnSiO₃</td><td>pink</td></tr><tr><td>Rhodochrosite / 菱锰矿</td><td>Mn²⁺</td><td>MnCO₃</td><td>rose-pink</td></tr></tbody></table><p><em>详见<a href="./intro.html">颜色成因总览</a>。</em></p>',8)])])}const p=d(o,[["render",i]]);export{m as __pageData,p as default};
